package assembly

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"strings"
)

// AtomType identifies the kind of knowledge stored in an atom.
type AtomType string

const (
	AtomTone       AtomType = "tone"
	AtomHooks      AtomType = "hooks"
	AtomPositioning AtomType = "positioning"
	AtomPersonas   AtomType = "personas"
	AtomObjections AtomType = "objections"
	AtomTiming     AtomType = "timing"
	AtomCompliance AtomType = "compliance"
	AtomStructure  AtomType = "structure"

	AtomProspectIntelligenceFramework AtomType = "prospect_intelligence_framework"
	AtomTransformation                AtomType = "transformation"
	AtomSignals                       AtomType = "signals"
	AtomInsightApproach               AtomType = "insight_approach"
)

// ValidAtomTypes is the set of recognized atom types.
var ValidAtomTypes = map[AtomType]bool{
	AtomTone:        true,
	AtomHooks:       true,
	AtomPositioning: true,
	AtomPersonas:    true,
	AtomObjections:  true,
	AtomTiming:      true,
	AtomCompliance:  true,
	AtomStructure:   true,

	AtomProspectIntelligenceFramework: true,
	AtomTransformation:                true,
	AtomSignals:                       true,
	AtomInsightApproach:               true,
}

// KnowledgeAtom is a single unit of assembled context.
type KnowledgeAtom struct {
	ID         int              `json:"id"`
	AtomType   AtomType         `json:"atom_type"`
	Scope      string           `json:"scope"`
	Content    json.RawMessage  `json:"content"`
	Source     string           `json:"source"`
	Confidence float64          `json:"confidence"`
	LastUsedAt string           `json:"last_used_at,omitempty"`
	UseCount   int              `json:"use_count"`
	CreatedAt  string           `json:"created_at"`
	UpdatedAt  string           `json:"updated_at"`
}

// SeedAtom inserts or updates a knowledge atom. If an atom with the same
// type+scope already exists, it updates the content and bumps confidence.
func SeedAtom(db *sql.DB, atomType AtomType, scope string, content json.RawMessage, source string) (int64, error) {
	if !ValidAtomTypes[atomType] {
		return 0, fmt.Errorf("invalid atom type: %s", atomType)
	}
	if !json.Valid(content) {
		return 0, fmt.Errorf("content must be valid JSON")
	}
	if source == "" {
		source = "setup"
	}

	// Upsert: update if same type+scope exists
	result, err := db.Exec(`
		INSERT INTO knowledge_atoms (atom_type, scope, content, source, confidence)
		VALUES (?, ?, ?, ?, 1.0)
		ON CONFLICT(atom_type, scope) DO UPDATE SET
			content = excluded.content,
			source = excluded.source,
			confidence = 1.0,
			updated_at = datetime('now')
	`, string(atomType), scope, string(content), source)
	if err != nil {
		// ON CONFLICT requires a unique index; fall back to check+insert/update
		return seedAtomFallback(db, atomType, scope, content, source)
	}
	return result.LastInsertId()
}

// seedAtomFallback handles the case where the unique constraint doesn't exist
// (first run before the composite unique index is added).
func seedAtomFallback(db *sql.DB, atomType AtomType, scope string, content json.RawMessage, source string) (int64, error) {
	var id int64
	err := db.QueryRow(
		`SELECT id FROM knowledge_atoms WHERE atom_type = ? AND scope = ?`,
		string(atomType), scope,
	).Scan(&id)

	if err == sql.ErrNoRows {
		result, err := db.Exec(
			`INSERT INTO knowledge_atoms (atom_type, scope, content, source, confidence) VALUES (?, ?, ?, ?, 1.0)`,
			string(atomType), scope, string(content), source,
		)
		if err != nil {
			return 0, fmt.Errorf("inserting atom: %w", err)
		}
		return result.LastInsertId()
	}
	if err != nil {
		return 0, fmt.Errorf("checking existing atom: %w", err)
	}

	_, err = db.Exec(
		`UPDATE knowledge_atoms SET content = ?, source = ?, confidence = 1.0, updated_at = datetime('now') WHERE id = ?`,
		string(content), source, id,
	)
	if err != nil {
		return 0, fmt.Errorf("updating atom: %w", err)
	}
	return id, nil
}

// QueryAtoms returns atoms matching the given type and optional scopes.
// Scopes are checked in order; the first match wins per type. If no scope
// matches, the global (empty scope) atom is returned.
func QueryAtoms(db *sql.DB, atomType AtomType, scopes ...string) ([]KnowledgeAtom, error) {
	// Build scope list: requested scopes + global fallback
	allScopes := make([]string, 0, len(scopes)+1)
	allScopes = append(allScopes, scopes...)
	allScopes = append(allScopes, "") // global fallback

	placeholders := make([]string, len(allScopes))
	args := make([]any, 0, len(allScopes)+1)
	args = append(args, string(atomType))
	for i, s := range allScopes {
		placeholders[i] = "?"
		args = append(args, s)
	}

	query := fmt.Sprintf(`
		SELECT id, atom_type, scope, content, source, confidence, last_used_at, use_count, created_at, updated_at
		FROM knowledge_atoms
		WHERE atom_type = ? AND scope IN (%s)
		ORDER BY confidence DESC, updated_at DESC
	`, strings.Join(placeholders, ","))

	rows, err := db.Query(query, args...)
	if err != nil {
		return nil, fmt.Errorf("querying atoms: %w", err)
	}
	defer rows.Close()

	var atoms []KnowledgeAtom
	for rows.Next() {
		var a KnowledgeAtom
		var content string
		if err := rows.Scan(&a.ID, &a.AtomType, &a.Scope, &content, &a.Source, &a.Confidence, &a.LastUsedAt, &a.UseCount, &a.CreatedAt, &a.UpdatedAt); err != nil {
			return nil, fmt.Errorf("scanning atom: %w", err)
		}
		a.Content = json.RawMessage(content)
		atoms = append(atoms, a)
	}
	return atoms, rows.Err()
}

// ListAtoms returns all atoms, optionally filtered by type.
func ListAtoms(db *sql.DB, filterType string) ([]KnowledgeAtom, error) {
	query := `SELECT id, atom_type, scope, content, source, confidence, last_used_at, use_count, created_at, updated_at
		FROM knowledge_atoms`
	var args []any
	if filterType != "" {
		query += ` WHERE atom_type = ?`
		args = append(args, filterType)
	}
	query += ` ORDER BY atom_type, scope, updated_at DESC`

	rows, err := db.Query(query, args...)
	if err != nil {
		return nil, fmt.Errorf("listing atoms: %w", err)
	}
	defer rows.Close()

	var atoms []KnowledgeAtom
	for rows.Next() {
		var a KnowledgeAtom
		var content string
		if err := rows.Scan(&a.ID, &a.AtomType, &a.Scope, &content, &a.Source, &a.Confidence, &a.LastUsedAt, &a.UseCount, &a.CreatedAt, &a.UpdatedAt); err != nil {
			return nil, fmt.Errorf("scanning atom: %w", err)
		}
		a.Content = json.RawMessage(content)
		atoms = append(atoms, a)
	}
	return atoms, rows.Err()
}

// TouchAtom records that an atom was used (increments use_count, updates last_used_at).
func TouchAtom(db *sql.DB, id int) error {
	_, err := db.Exec(
		`UPDATE knowledge_atoms SET use_count = use_count + 1, last_used_at = datetime('now') WHERE id = ?`,
		id,
	)
	return err
}

// DeleteAtom removes a knowledge atom by ID.
func DeleteAtom(db *sql.DB, id int) error {
	_, err := db.Exec(`DELETE FROM knowledge_atoms WHERE id = ?`, id)
	return err
}

