168→// extractContent tries to pretty-print JSON content; falls back to raw string.
169→func extractContent(raw json.RawMessage) string {
170→	// Try to unmarshal as a string first (common for text atoms)
171→	var s string
172→	if err := json.Unmarshal(raw, &s); err == nil {
173→		return s
174→	}
175→	// Return formatted JSON for structured atoms
176→	var pretty json.RawMessage
177→	if err := json.Unmarshal(raw, &pretty); err == nil {
178→		indented, err := json.MarshalIndent(pretty, "", "  ")
179→		if err == nil {
180→			return string(indented)
181→		}
182→	}
183→	return string(raw)
184→}
