223→// queryLearningsByTypes fetches learnings, optionally filtered by type, newest first.
224→func queryLearningsByTypes(database *sql.DB, types []string, limit int) ([]Learning, error) {
225→	var query string
226→	var args []any
227→
228→	if len(types) == 0 {
229→		query = `SELECT id, type, content, source_session, created_at FROM learnings ORDER BY created_at DESC LIMIT ?`
230→		args = append(args, limit)
231→	} else {
232→		placeholders := make([]string, len(types))
233→		for i, t := range types {
234→			placeholders[i] = "?"
235→			args = append(args, t)
236→		}
237→		query = fmt.Sprintf(
238→			`SELECT id, type, content, source_session, created_at FROM learnings WHERE type IN (%s) ORDER BY created_at DESC LIMIT ?`,
239→			strings.Join(placeholders, ","),
240→		)
241→		args = append(args, limit)
242→	}
243→
244→	rows, err := database.Query(query, args...)
245→	if err != nil {
246→		return nil, fmt.Errorf("querying learnings: %w", err)
247→	}
248→	defer rows.Close()
249→
250→	var learnings []Learning
251→	for rows.Next() {
252→		var l Learning
253→		if err := rows.Scan(&l.ID, &l.Type, &l.Content, &l.SourceSession, &l.CreatedAt); err != nil {
254→			return nil, fmt.Errorf("scanning learning: %w", err)
255→		}
256→		learnings = append(learnings, l)
257→	}
258→	return learnings, rows.Err()
259→}
