297→		}
298→		if v, ok := cfg.Settings["icp.company_size"]; ok && v != "" {
299→			lines = append(lines, fmt.Sprintf("**ICP Company Size:** %s", v))
300→		}
301→		if v, ok := cfg.Settings["sender.name"]; ok && v != "" {
302→			lines = append(lines, fmt.Sprintf("**Sender:** %s", v))
303→		}
304→		if v, ok := cfg.Settings["sender.email"]; ok && v != "" {
305→			lines = append(lines, fmt.Sprintf("**From:** %s", v))
