package assembly

import (
	"database/sql"
	"encoding/json"
	"strings"
	"testing"

	"github.com/usenurge/nurgesh/internal/db"
	_ "modernc.org/sqlite"
)

func setupTestDB(t *testing.T) *sql.DB {
	t.Helper()
	d, err := sql.Open("sqlite", ":memory:")
	if err != nil {
		t.Fatal(err)
	}
	if _, err := d.Exec(db.Schema); err != nil {
		t.Fatal(err)
	}
	if err := db.EnsureMigrations(d); err != nil {
		t.Fatal(err)
	}
	return d
}

func TestAssembleInvalidTask(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	_, err := Assemble(d, AssembleRequest{Task: "invalid_task"})
	if err == nil {
		t.Fatal("expected error for invalid task type")
	}
	if !strings.Contains(err.Error(), "unknown task type") {
		t.Fatalf("unexpected error: %v", err)
	}
}

func TestAssembleEmptyDB(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	// Assemble with no data at all — should succeed with minimal output
	InvalidateCache()
	result, err := Assemble(d, AssembleRequest{Task: TaskPipeline})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if result.Cached {
		t.Fatal("expected non-cached result on first call")
	}
	// Pipeline has no required atoms, so context may be minimal
	if result.TokenEstimate < 0 {
		t.Fatal("token estimate should be non-negative")
	}
}

func TestAssembleWithAtoms(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()
	InvalidateCache()

	// Seed tone and structure atoms
	_, err := SeedAtom(d, AtomTone, "", json.RawMessage(`"Be conversational, warm, and direct. No corporate jargon."`), "test")
	if err != nil {
		t.Fatalf("seeding tone atom: %v", err)
	}
	_, err = SeedAtom(d, AtomStructure, "", json.RawMessage(`"50-90 words. Hook, value prop, CTA. No filler."`), "test")
	if err != nil {
		t.Fatalf("seeding structure atom: %v", err)
	}
	_, err = SeedAtom(d, AtomHooks, "", json.RawMessage(`"Reference a recent event, mutual connection, or specific pain point."`), "test")
	if err != nil {
		t.Fatalf("seeding hooks atom: %v", err)
	}

	result, err := Assemble(d, AssembleRequest{Task: TaskOutbound})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if !strings.Contains(result.Context, "## Tone") {
		t.Error("expected Tone section in output")
	}
	if !strings.Contains(result.Context, "## Structure") {
		t.Error("expected Structure section in output")
	}
	if !strings.Contains(result.Context, "## Hooks") {
		t.Error("expected Hooks section in output")
	}
	if len(result.AtomsLoaded) != 3 {
		t.Errorf("expected 3 atoms loaded, got %d", len(result.AtomsLoaded))
	}
}

func TestAssembleWithProspect(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()
	InvalidateCache()

	// Insert a contact
	_, err := d.Exec(`
		INSERT INTO contacts (id, source, email, name, domain, company, title, lead_status, tier, tier_score, industry)
		VALUES ('c1', 'gmail', 'john@acme.com', 'John Doe', 'acme.com', 'Acme Corp', 'CTO', 'new', 1, 85.0, 'saas')
	`)
	if err != nil {
		t.Fatalf("inserting contact: %v", err)
	}

	// Seed a tone atom
	_, err = SeedAtom(d, AtomTone, "", json.RawMessage(`"Keep it brief and direct."`), "test")
	if err != nil {
		t.Fatalf("seeding atom: %v", err)
	}

	result, err := Assemble(d, AssembleRequest{
		Task:     TaskOutbound,
		Prospect: "john@acme.com",
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	// Should contain prospect info
	if !strings.Contains(result.Context, "john@acme.com") {
		t.Error("expected prospect email in context")
	}
	if !strings.Contains(result.Context, "Acme Corp") {
		t.Error("expected company name in context")
	}
	if !strings.Contains(result.Context, "CTO") {
		t.Error("expected title in context")
	}

	// Should have research_required directive for Tier 1 without dossier
	found := false
	for _, d := range result.Directives {
		if strings.Contains(d, "research_required") {
			found = true
			break
		}
	}
	if !found {
		t.Error("expected research_required directive for Tier 1 prospect without dossier")
	}

	// Should have enrich_required directive since enriched_at is empty
	foundEnrich := false
	for _, d := range result.Directives {
		if strings.Contains(d, "enrich_required") {
			foundEnrich = true
			break
		}
	}
	if !foundEnrich {
		t.Error("expected enrich_required directive for unenriched contact")
	}
}

func TestAssembleWithDossier(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()
	InvalidateCache()

	// Insert contact and dossier
	d.Exec(`INSERT INTO contacts (id, source, email, name, domain, company, title, tier, enriched_at)
		VALUES ('c1', 'gmail', 'jane@bigco.com', 'Jane Smith', 'bigco.com', 'BigCo', 'VP Sales', 2, '2026-03-01')`)

	err := SaveDossier(d, "jane@bigco.com", "Jane Smith", "bigco.com",
		json.RawMessage(`"BigCo recently raised Series B. Jane was promoted to VP Sales 3 months ago. They use Salesforce."`),
		2, "deep")
	if err != nil {
		t.Fatalf("saving dossier: %v", err)
	}

	result, err := Assemble(d, AssembleRequest{
		Task:     TaskOutbound,
		Prospect: "jane@bigco.com",
	})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if !strings.Contains(result.Context, "## Research") {
		t.Error("expected Research section when dossier exists")
	}
	if !strings.Contains(result.Context, "Series B") {
		t.Error("expected dossier content in output")
	}

	// Should NOT have research_required since dossier exists
	for _, dir := range result.Directives {
		if strings.Contains(dir, "research_required") {
			t.Error("should not have research_required when dossier exists")
		}
	}
}

func TestAssembleCaching(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()
	InvalidateCache()

	_, err := SeedAtom(d, AtomTone, "", json.RawMessage(`"Test tone."`), "test")
	if err != nil {
		t.Fatal(err)
	}

	// First call
	r1, err := Assemble(d, AssembleRequest{Task: TaskOutbound})
	if err != nil {
		t.Fatal(err)
	}
	if r1.Cached {
		t.Error("first call should not be cached")
	}

	// Second call — should be cached
	r2, err := Assemble(d, AssembleRequest{Task: TaskOutbound})
	if err != nil {
		t.Fatal(err)
	}
	if !r2.Cached {
		t.Error("second call should be cached")
	}
	if r2.Context != r1.Context {
		t.Error("cached context should match original")
	}

	// After invalidation — should not be cached
	InvalidateCache()
	r3, err := Assemble(d, AssembleRequest{Task: TaskOutbound})
	if err != nil {
		t.Fatal(err)
	}
	if r3.Cached {
		t.Error("should not be cached after invalidation")
	}
}

func TestAssembleWithLearnings(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()
	InvalidateCache()

	// Insert learnings
	d.Exec(`INSERT INTO learnings (type, content, source_session) VALUES ('tone', 'User prefers casual tone', 'sess-1')`)
	d.Exec(`INSERT INTO learnings (type, content, source_session) VALUES ('style', 'Shorter emails work better', 'sess-1')`)

	result, err := Assemble(d, AssembleRequest{Task: TaskOutbound})
	if err != nil {
		t.Fatal(err)
	}

	if !strings.Contains(result.Context, "## Recent Learnings") {
		t.Error("expected Recent Learnings section")
	}
	if !strings.Contains(result.Context, "casual tone") {
		t.Error("expected learning content in output")
	}
}

func TestAssembleScopedAtoms(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()
	InvalidateCache()

	// Seed a global tone and a CTO-scoped tone
	SeedAtom(d, AtomTone, "", json.RawMessage(`"Global default tone."`), "test")
	SeedAtom(d, AtomTone, "cto", json.RawMessage(`"Executive-level brevity. No fluff."`), "test")

	// Insert a CTO contact
	d.Exec(`INSERT INTO contacts (id, source, email, name, title, tier)
		VALUES ('c1', 'gmail', 'cto@startup.com', 'Alice', 'CTO', 1)`)

	result, err := Assemble(d, AssembleRequest{
		Task:     TaskOutbound,
		Prospect: "cto@startup.com",
	})
	if err != nil {
		t.Fatal(err)
	}

	// Should get the CTO-scoped atom (higher specificity match)
	if !strings.Contains(result.Context, "Executive-level brevity") {
		t.Error("expected CTO-scoped tone atom for CTO prospect")
	}
}

func TestAssembleUnknownProspect(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()
	InvalidateCache()

	result, err := Assemble(d, AssembleRequest{
		Task:     TaskOutbound,
		Prospect: "unknown@nowhere.com",
	})
	if err != nil {
		t.Fatal(err)
	}

	// Should have enrich_required directive
	found := false
	for _, dir := range result.Directives {
		if strings.Contains(dir, "enrich_required") {
			found = true
			break
		}
	}
	if !found {
		t.Error("expected enrich_required directive for unknown prospect")
	}
}

func TestAssembleNonProspectTask(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()
	InvalidateCache()

	// Pipeline, analytics, hygiene etc. should work without a prospect
	for _, task := range []TaskType{TaskPipeline, TaskAnalytics, TaskHygiene, TaskSendHealth, TaskReview} {
		InvalidateCache()
		result, err := Assemble(d, AssembleRequest{Task: task})
		if err != nil {
			t.Fatalf("task %s: unexpected error: %v", task, err)
		}
		if result == nil {
			t.Fatalf("task %s: nil result", task)
		}
	}
}

func TestEstimateTokens(t *testing.T) {
	text := "This is a ten word sentence with exactly ten words"
	est := estimateTokens(text)
	// 10 words * 1.3 = 13
	if est != 13 {
		t.Errorf("expected 13 tokens, got %d", est)
	}

	empty := estimateTokens("")
	if empty != 0 {
		t.Errorf("expected 0 tokens for empty string, got %d", empty)
	}
}

func TestBuildScopes(t *testing.T) {
	// Nil contact
	scopes := buildScopes(nil)
	if len(scopes) != 0 {
		t.Error("nil contact should return no scopes")
	}

	// Full contact
	c := &Contact{
		Title:    "CTO",
		Tier:     1,
		Industry: "SaaS",
		Domain:   "acme.com",
	}
	scopes = buildScopes(c)
	if len(scopes) != 4 {
		t.Errorf("expected 4 scopes, got %d: %v", len(scopes), scopes)
	}
	if scopes[0] != "cto" {
		t.Errorf("first scope should be normalized title, got %q", scopes[0])
	}
	if scopes[1] != "tier_1" {
		t.Errorf("second scope should be tier, got %q", scopes[1])
	}
}

func TestExtractContent(t *testing.T) {
	// String JSON
	s := extractContent(json.RawMessage(`"hello world"`))
	if s != "hello world" {
		t.Errorf("expected 'hello world', got %q", s)
	}

	// Object JSON
	o := extractContent(json.RawMessage(`{"key":"value"}`))
	if !strings.Contains(o, "key") {
		t.Errorf("expected key in output, got %q", o)
	}
}

