		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		atoms, err := assembly.ListAtoms(d, filterType)
		if err != nil {
			return err
		}

		if knowledgeFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(atoms)
		}

		if len(atoms) == 0 {
			fmt.Println("No knowledge atoms found.")
			return nil
		}

		for _, a := range atoms {
			scope := a.Scope
			if scope == "" {
				scope = "global"
			}
