	d.Exec(`INSERT INTO contacts (id, source, email, name, domain, company, title, tier, enriched_at)
		VALUES ('c1', 'gmail', 'jane@bigco.com', 'Jane Smith', 'bigco.com', 'BigCo', 'VP Sales', 2, '2026-03-01')`)

	err := SaveDossier(d, "jane@bigco.com", "Jane Smith", "bigco.com",
		json.RawMessage(`"BigCo recently raised Series B. Jane was promoted to VP Sales 3 months ago. They use Salesforce."`),
