func TestAssembleCaching(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()
	InvalidateCache()

	_, err := SeedAtom(d, AtomTone, "", json.RawMessage(`"Test tone."`), "test")
	if err != nil {
		t.Fatal(err)
	}

	// First call
	r1, err := Assemble(d, AssembleRequest{Task: TaskOutbound})
	if err != nil {
		t.Fatal(err)
	}
	if r1.Cached {
		t.Error("first call should not be cached")
	}

	// Second call — should be cached
	r2, err := Assemble(d, AssembleRequest{Task: TaskOutbound})
	if err != nil {
		t.Fatal(err)
	}
	if !r2.Cached {
		t.Error("second call should be cached")
	}
	if r2.Context != r1.Context {
		t.Error("cached context should match original")
	}

	// After invalidation — should not be cached
	InvalidateCache()
	r3, err := Assemble(d, AssembleRequest{Task: TaskOutbound})
	if err != nil {
		t.Fatal(err)
	}
	if r3.Cached {
		t.Error("should not be cached after invalidation")
	}
}

