func TestEstimateTokens(t *testing.T) {
	text := "This is a ten word sentence with exactly ten words"
	est := estimateTokens(text)
	// 10 words * 1.3 = 13
	if est != 13 {
		t.Errorf("expected 13 tokens, got %d", est)
	}

	empty := estimateTokens("")
	if empty != 0 {
		t.Errorf("expected 0 tokens for empty string, got %d", empty)
	}
}

func TestBuildScopes(t *testing.T) {
	// Nil contact
	scopes := buildScopes(nil)
	if len(scopes) != 0 {
		t.Error("nil contact should return no scopes")
	}

	// Full contact
	c := &Contact{
		Title:    "CTO",
		Tier:     1,
		Industry: "SaaS",
		Domain:   "acme.com",
	}
	scopes = buildScopes(c)
	if len(scopes) != 4 {
		t.Errorf("expected 4 scopes, got %d: %v", len(scopes), scopes)
	}
	if scopes[0] != "cto" {
		t.Errorf("first scope should be normalized title, got %q", scopes[0])
	}
	if scopes[1] != "tier_1" {
		t.Errorf("second scope should be tier, got %q", scopes[1])
	}
}

func TestExtractContent(t *testing.T) {
	// String JSON
	s := extractContent(json.RawMessage(`"hello world"`))
	if s != "hello world" {
		t.Errorf("expected 'hello world', got %q", s)
	}

	// Object JSON
	o := extractContent(json.RawMessage(`{"key":"value"}`))
	if !strings.Contains(o, "key") {
		t.Errorf("expected key in output, got %q", o)
	}
}

