110→// pickBestAtom selects the most relevant atom from candidates.
111→// It prefers scoped matches over the global fallback. Among scoped matches,
112→// it picks the one whose scope appears earliest in the scopes list
113→// (most specific first). Falls back to confidence/recency ordering.
114→func pickBestAtom(atoms []KnowledgeAtom, scopes []string) KnowledgeAtom {
115→	if len(atoms) == 1 {
116→		return atoms[0]
117→	}
118→
119→	// Build scope priority: lower index = higher priority
120→	scopePrio := make(map[string]int, len(scopes))
121→	for i, s := range scopes {
122→		scopePrio[s] = i
123→	}
124→
125→	best := atoms[0]
126→	bestPrio := len(scopes) + 1 // global ("") gets worst priority
127→	if p, ok := scopePrio[best.Scope]; ok {
128→		bestPrio = p
129→	}
130→
131→	for _, a := range atoms[1:] {
132→		prio := len(scopes) + 1
133→		if p, ok := scopePrio[a.Scope]; ok {
134→			prio = p
135→		}
136→		if prio < bestPrio {
137→			best = a
138→			bestPrio = prio
139→		}
140→	}
141→	return best
142→}
