144→// atomHeading maps atom types to markdown section headings.
145→func atomHeading(at AtomType) string {
146→	switch at {
147→	case AtomTone:
148→		return "Tone"
149→	case AtomHooks:
150→		return "Hooks"
151→	case AtomPositioning:
152→		return "Positioning"
153→	case AtomPersonas:
154→		return "Personas"
155→	case AtomObjections:
156→		return "Objections"
157→	case AtomSignals:
158→		return "Signals"
159→	case AtomCompliance:
160→		return "Compliance"
161→	default:
162→		return string(at)
163→	}
164→}
