184→// queryRecentLearnings returns recent learnings relevant to the task.
185→func queryRecentLearnings(database *sql.DB, task TaskType, limit int) ([]Learning, error) {
186→	// Map tasks to relevant learning types
187→	learningTypes := taskLearningTypes(task)
188→	if len(learningTypes) == 0 {
189→		// Fallback: grab the most recent learnings of any type
190→		return queryLearningsByTypes(database, nil, limit)
191→	}
192→	return queryLearningsByTypes(database, learningTypes, limit)
193→}
