204→	case TaskResearch, TaskQualify:
205→		return []string{"icp", "positioning", "preference"}
206→	case TaskPipeline:
207→		return []string{"preference", "workflow"}
208→	case TaskAnalytics, TaskReview:
209→		return []string{"preference", "metric"}
210→	case TaskProspects, TaskICP, TaskPersonas:
