284→		if v, ok := cfg.Settings["product.name"]; ok && v != "" {
285→			lines = append(lines, fmt.Sprintf("**Product:** %s", v))
286→		}
287→		if v, ok := cfg.Settings["product.url"]; ok && v != "" {
288→			lines = append(lines, fmt.Sprintf("**Website:** %s", v))
289→		}
290→		if v, ok := cfg.Settings["icp.titles"]; ok && v != "" {
