292→		}
293→		if v, ok := cfg.Settings["icp.industries"]; ok && v != "" {
294→			lines = append(lines, fmt.Sprintf("**ICP Industries:** %s", v))
295→		}
296→		if v, ok := cfg.Settings["icp.company_size"]; ok && v != "" {
297→			lines = append(lines, fmt.Sprintf("**ICP Company Size:** %s", v))
298→		}
299→		if v, ok := cfg.Settings["sender.name"]; ok && v != "" {
300→			lines = append(lines, fmt.Sprintf("**Sender:** %s", v))
301→		}
302→		if v, ok := cfg.Settings["sender.email"]; ok && v != "" {
303→			lines = append(lines, fmt.Sprintf("**From:** %s", v))
304→		}
305→
306→		// Task-specific settings
307→		switch task {
308→		case TaskHygiene, TaskSendHealth:
309→			if v, ok := cfg.Settings["sending.daily_cap"]; ok && v != "" {
310→				lines = append(lines, fmt.Sprintf("**Daily Cap:** %s", v))
311→			}
312→		case TaskSequence:
