package session

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"strings"
)

// DistillResult summarizes the outcome of distilling raw learnings into
// knowledge atom updates and strategic memory entries.
type DistillResult struct {
	LearningsProcessed int      `json:"learnings_processed"`
	AtomsUpdated       int      `json:"atoms_updated"`
	AtomsCreated       int      `json:"atoms_created"`
	Categories         []string `json:"categories"`
}

// learningTypeToAtomTypes maps learning types to the knowledge atom types they
// should be appended to.
var learningTypeToAtomTypes = map[string][]string{
	"tone":       {"tone"},
	"icp":        {"personas", "positioning"},
	"product":    {"positioning"},
	"pattern":    {"hooks", "structure"},
	"preference": {}, // preferences are context-dependent; handled specially
}

// Distill processes undistilled learnings, appending them to the relevant
// knowledge atoms and strategic memory entries, then marks them as distilled.
//
// The operation is mechanical: learning content is appended to a "learnings"
// array inside each matching atom's JSON content. This preserves the original
// atom content while accumulating session insights.
func Distill(db *sql.DB) (*DistillResult, error) {
	result := &DistillResult{}

	// 1. Load undistilled learnings
	learnings, err := listUndistilledLearnings(db)
	if err != nil {
		return nil, fmt.Errorf("loading undistilled learnings: %w", err)
	}
	if len(learnings) == 0 {
		return result, nil
	}

	// 2. Group by type
	groups := map[string][]Learning{}
	for _, l := range learnings {
		groups[l.Type] = append(groups[l.Type], l)
	}

	// 3. Process each group
	categorySet := map[string]bool{}
	for typ, items := range groups {
		categorySet[typ] = true

		switch typ {
		case "competitor":
			// Competitors go to strategic memory
			for _, l := range items {
				if err := saveCompetitorMemory(db, l); err != nil {
					return nil, fmt.Errorf("saving competitor memory: %w", err)
				}
			}

		case "preference":
			// Preferences: try to match to relevant atom types based on content keywords
